- - - - - -

/* Code by Aly#1293 for Daze#35386 */


/* - - - Global Styling - - - */ 
*, div { letter-spacing: 0.02rem; }
table, tr, td { margin: 0; padding: 0; background: none; border: 0; font-size: 12px; letter-spacing: 0.025rem;}
.quote, .quote-body { display: inline-block; width: 100%; margin: 0; padding: 0; border: 0; background: none; }

/* - - - Setup - - - */
strike + div  { margin: -1.25rem; background: #f8d0a1; overflow: hidden; }
em + div .quote + div u + table td p + p + div { display: block; width: 100%; margin: 0; padding: 0; background: none; }

td p { margin: 0; padding: 0; }
td p + p { font-size: 9px; font-family: Georgia, serif; font-style: italic; opacity: 0.5; margin-bottom: 5px; }
em + div + div { margin: 0; padding: 0px; width: 100%; }

/* - - - Outer Container - - - */
strike + div em + div { margin: 0px auto 0 auto; width: 80%; padding-top: 20px; padding-bottom: 0px; display: block; }

/* - - - Inner Container - - - */
.quote { display: block; width: 100%; height: 40px; overflow: hidden; border-radius: 1rem 1rem 0 0; }
.quote img { width: 100%; }

/* - - - Main Content - - - */
.quote + div { display: block; width: 100%; background-color: #fff; padding: 40px; border-radius: 0 0 1rem 1rem; }

/* - - - Circle Navigation - - - */
em + div .quote + div u + table td p + p + div a {
margin: 10px 5px 0 5px; padding: 0; width: 10px; height: 10px; border-radius: 100%; background: #d9dce7; display: inline-block; }
em + div .quote + div u + table td p + p + div a:hover { border: 2px solid white; background: #b6c9d9;  }

/* - - - Footer Links - - - */
em + div + div a { vertical-align: top; display: inline-block; margin: 0 5px; padding: 2px 10px; font-size: 9px; text-transform: uppercase; letter-spacing: 0.05rem; background: #f3ece0; color: #b7aa9f; border-radius: 0 0 0.5rem 0.5rem; }
em + div + div a:hover { background: #b6c9d9; color: #fff; }

use Spatie\Image\Image;
use Spatie\Image\Enums\AlignPosition;
use Spatie\Image\Enums\Unit;

Image::load(storage_path('app/public/input.jpg'))
    // 1. Größe anpassen (Fit kombiniert Resize & Crop)
    ->fit(800, 600)
    
    // 2. Text mit Hintergrund hinzufügen
    // Spatie erlaubt es, Text-Eigenschaften in einer Closure zu definieren
    ->text('Ihr Text hier', function($font) {
        $font->file(public_path('fonts/Roboto-Bold.ttf'))
             ->size(40)
             ->color('ffffff')
             ->width(700) // Maximale Breite des Textblocks
             ->align(AlignPosition::Center)
             // Hier tricksen wir: Der Hintergrund wird direkt am Text ausgerichtet
             ->background('rgba(0, 0, 0, 0.6)') 
             ->padding(20); // Abstand zwischen Text und Hintergrundbox
    })
    
    // Position des Textblocks auf dem Gesamtbild
    ->textPosition(AlignPosition::Bottom) 
    
    ->save(storage_path('app/public/output.jpg'));
